use html_to_markdown_rs::convert;

#[test]
fn test_empty_html() {
    // Empty HTML document
    let html = r#"<html><head></head><body></body></html>"#;
    let result = convert(html, None).expect("conversion should succeed");
    let content = result.content.unwrap_or_default();

    assert_eq!(content.trim(), "", "content_equals mismatch");
}

#[test]
fn test_encoding_cjk_characters() {
    // CJK (Chinese, Japanese, Korean) characters are preserved
    let html = r#"<p>中文内容</p><p>日本語テキスト</p><p>한국어 텍스트</p>"#;
    let result = convert(html, None).expect("conversion should succeed");
    let content = result.content.unwrap_or_default();

    assert!(!content.trim().is_empty(), "expected non-empty content");
    assert!(content.contains("中文内容"), "expected content to contain: 中文内容");
    assert!(
        content.contains("日本語テキスト"),
        "expected content to contain: 日本語テキスト"
    );
    assert!(
        content.contains("한국어 텍스트"),
        "expected content to contain: 한국어 텍스트"
    );
}

